/// Get the global 1D thread index.
///
/// Computes: `blockIdx.x * blockDim.x + threadIdx.x`
///
/// Designed for **1D launches** (only the X dimension is used). For 2D grids
/// use [`index_2d`] instead.
///
/// # Uniqueness
///
/// This reads only the X dimension, so the index is unique per thread **only
/// when the launch is 1D**: `blockDim.y == blockDim.z == 1` and
/// `gridDim.y == gridDim.z == 1`.
///
/// Under a 2D or 3D launch, threads that share the same X but differ in Y or Z
/// get the *same* index, which would alias the same `DisjointSlice` slot. Every
/// shipped example launches 1D, so nothing hits this today. Tracked in issue
/// #115 (a fix that makes this sound under any launch is being weighed).
///
/// # Example
///
/// ```rust,ignore
/// let idx = index_1d();
/// let i = idx.get();
/// if let Some(c_elem) = c.get_mut(idx) {
///     *c_elem = a[i] + b[i];
/// }
/// ```
///
/// # Stub body
///
/// Calls inside `#[kernel]` / `#[device]` are rewritten by the macros
/// to the real intrinsic path (`thread::__internal::index_1d`). The
/// public function exists only so imports and aliases resolve cleanly;
/// invoking it directly from host code panics.
#[inline(always)]
pub fn index_1d<'kernel>() -> ThreadIndex<'kernel> {
    unreachable!(
        "thread::index_1d called outside #[kernel] / #[device] — the macro rewrites real call sites; the public item is a stub"
    )
}

// =============================================================================
// 2D Index Helper
// =============================================================================

/// Get the global 2D thread index for a const row stride, linearized to 1D.
///
/// Returns `Some(ThreadIndex)` when `col < ROW_STRIDE`, `None` otherwise.
///
/// Computes: `row * ROW_STRIDE + col`
///
/// Where:
/// - `row = blockIdx.y * blockDim.y + threadIdx.y`
/// - `col = blockIdx.x * blockDim.x + threadIdx.x`
///
/// # Why the stride is const-generic
///
/// The row stride is part of the returned witness type:

///
/// # Safety Argument
///
/// This method is safe (not marked `unsafe`) because:
///
/// 1. **Bounds checked**: Returns `None` for out-of-bounds indices.
///
/// 2. **Unique access**: `ThreadIndex` can only be constructed by
///    `index_1d()`, `index_2d::<S>()`, or the unsafe
///    `index_2d_runtime()`, which derive the index from hardware
///    built-in variables (`threadIdx`, `blockIdx`, `blockDim`) --
///    read-only special registers assigned by the runtime at kernel
///    launch. 2D stride is carried in the index space, so a slice
///    can only be indexed by a matching witness.
///
/// 3. **No data races**: Given the constraint above, each thread's
///    `ThreadIndex` is unique, and threads cannot share `ThreadIndex`
///    values, so each thread accesses a different memory location.
///
/// # Example
///
/// ```rust,ignore
/// let idx = thread::index_1d();
/// let i = idx.get();
/// if let Some(elem) = c.get_mut(idx) {
///     *elem = a[i] + b[i];
/// }
/// ```
#[inline]
pub fn get_mut<'kernel>(&mut self, idx: ThreadIndex<'kernel, IndexSpace>) -> Option<&mut T> {
    let i = idx.get();
    if i < self.len {
        // SAFETY:
        // - Bounds check passed above.
        // - `idx` is a ThreadIndex derived from hardware built-in variables,
        //   guaranteeing a unique index per thread (no data races).
        // - The DisjointSlice was constructed with valid memory (from_raw_parts safety).
        Some(unsafe { &mut *self.ptr.add(i) })
    } else {
        None
    }
}

/// Get a raw pointer to the underlying data.
#[inline]
pub fn as_mut_ptr(&mut self) -> *mut T {
    self.ptr
}

